input.value:
fetch logs
| filter in(log.source, "palo-alto-firewall", "cisco-asa", "fortinet-fortigate")
| fieldsAdd vendor = if(log.source == "palo-alto-firewall", "Palo Alto",
                     else: if(log.source == "cisco-asa", "Cisco ASA",
                     else: "Fortinet"))
| summarize total = count(),
            by: { vendor }
| sort total desc

fetch logs
| filter in(log.source, "palo-alto-firewall", "cisco-asa", "fortinet-fortigate")
| fieldsAdd vendor = if(log.source == "palo-alto-firewall", "Palo Alto",
                     else: if(log.source == "cisco-asa", "Cisco ASA",
                     else: "Fortinet")),
           raw_action = if(log.source == "palo-alto-firewall", paloalto.action,
                         else: if(log.source == "cisco-asa", cisco.action,
                         else: fortinet.action))
| fieldsAdd is_blocked = NOT in(raw_action, "allow", "permit", "built", "accept", "teardown", "ssl-login-succeed", "login", "logout", "config-change")
| summarize total = count(),
            blocked = countIf(is_blocked),
            by: { vendor }
| fieldsAdd block_rate = round(toDouble(blocked) / toDouble(total) * 100, decimals: 1)
| sort block_rate desc

fetch logs
| filter in(log.source, "palo-alto-firewall", "cisco-asa", "fortinet-fortigate")
| fieldsAdd vendor = if(log.source == "palo-alto-firewall", "Palo Alto",
                     else: if(log.source == "cisco-asa", "Cisco ASA",
                     else: "Fortinet")),
           raw_action = if(log.source == "palo-alto-firewall", paloalto.action,
                         else: if(log.source == "cisco-asa", cisco.action,
                         else: fortinet.action))
| fieldsAdd is_blocked = NOT in(raw_action, "allow", "permit", "built", "accept", "teardown", "ssl-login-succeed", "login", "logout", "config-change")
| makeTimeseries palo_alto = countIf(vendor == "Palo Alto" AND is_blocked),
                 cisco_asa = countIf(vendor == "Cisco ASA" AND is_blocked),
                 fortinet = countIf(vendor == "Fortinet" AND is_blocked),
                 interval: 5m

fetch logs
| filter in(log.source, "palo-alto-firewall", "cisco-asa", "fortinet-fortigate")
| fieldsAdd vendor = if(log.source == "palo-alto-firewall", "Palo Alto",
                     else: if(log.source == "cisco-asa", "Cisco ASA",
