fetch logs
| filter in(log.source, "palo-alto-firewall", "cisco-asa", "fortinet-fortigate")
| fieldsAdd vendor = if(log.source == "palo-alto-firewall", "Palo Alto",
                     else: if(log.source == "cisco-asa", "Cisco ASA",
                     else: "Fortinet")),
           src = if(log.source == "palo-alto-firewall", paloalto.src,
                 else: if(log.source == "cisco-asa", cisco.src_ip,
                 else: fortinet.srcip)),
           raw_action = if(log.source == "palo-alto-firewall", paloalto.action,
                         else: if(log.source == "cisco-asa", cisco.action,
                         else: fortinet.action))
| filter NOT in(raw_action, "allow", "permit", "built", "accept", "teardown", "ssl-login-succeed", "login", "logout", "config-change")
| summarize block_count = count(),
            vendors = collectDistinct(vendor),
            by: { src }
| sort block_count desc
| limit 20

fetch logs
